// Security Configuration
@Configuration
@EnableWebSecurity
class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf().disable() // Disable CSRF for SAML ACS endpoint
            .authorizeRequests(authorizeRequests ->
                authorizeRequests
                    .antMatchers("/saml/acs").permitAll() // Allow IdP to post to ACS without authentication
                    .antMatchers("/").authenticated() // Other paths require authentication
                    .antMatchers("/user-info").authenticated()
                    .anyRequest().authenticated()
            )
            .formLogin() // Enable form login for general use after SAML auth
            .and()
            .logout(logout -> logout
                .logoutSuccessUrl("/login?logout")
                .permitAll()
            );

        // A custom filter could be added here to handle the authentication result
        // For this example, we directly set the SecurityContext in SamlProcessorService.
        return http.build();
    }
}

// Custom Authentication Token
class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String principal;
    private final Map<String, String> attributes;

    public SamlAuthenticationToken(String principal, Collection<? extends GrantedAuthority> authorities, Map<String, String> attributes) {
        super(authorities);
        this.principal = principal;
        this.attributes = attributes;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return null; // SAML doesn't have a direct password credential
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    public Map<String, String> getAttributes() {
        return attributes;
    }
}

// SAML Service Provider Controller
@RestController
class SamlController {

    private static final Logger logger = Logger.getLogger(SamlController.class.getName());
    private final SamlProcessorService samlProcessorService;

    public SamlController(SamlProcessorService samlProcessorService) {
        this.samlProcessorService = samlProcessorService;
    }

    @PostMapping(value = "/saml/acs", consumes = "application/x-www-form-urlencoded")
    public String samlAssertionConsumerService(@RequestBody String samlResponseEncoded, HttpSession session) {
        logger.info("Received SAML ACS request.");

        try {
            // Extract the SAMLResponse parameter from the URL-encoded body
            String samlResponseParam = Arrays.stream(samlResponseEncoded.split("&"))
                .filter(param -> param.startsWith("SAMLResponse="))
                .findFirst()
                .map(param -> param.substring("SAMLResponse=".length()))
                .orElseThrow(() -> new IllegalArgumentException("SAMLResponse parameter not found."));

            // URL decode and then process
            String decodedSamlResponseParam = java.net.URLDecoder.decode(samlResponseParam, StandardCharsets.UTF_8.name());

            Map<String, String> userAttributes = samlProcessorService.processSamlResponse(decodedSamlResponseParam, session);
            session.setAttribute("samlUserAttributes", userAttributes); // Store attributes in session

            logger.info("SAML Response processed successfully for user: " + userAttributes.get("NameID"));
            return "<!DOCTYPE html><html><head><meta http-equiv='refresh' content='0; URL=/'></head><body>Redirecting...</body></html>"; // Redirect to authenticated home
        } catch (Exception e) {
            logger.severe("Error processing SAML response: " + e.getMessage());
            e.printStackTrace();
            return "Error processing SAML response: " + e.getMessage(); // Handle error gracefully
        }
    }

    @GetMapping("/")
    public String home(HttpSession session) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication != null && authentication.isAuthenticated() && !(authentication instanceof AnonymousAuthenticationToken)) {
            Map<String, String> attributes = (Map<String, String>) session.getAttribute("samlUserAttributes");
            String username = attributes != null ? attributes.get("NameID") : authentication.getName();
            return "<h1>Welcome, " + username + "!</h1>" +
                   "<p>You are authenticated via SAML.</p>" +
                   "<p><a href='/user-info'>View User Info</a></p>" +
                   "<p><a href='/logout'>Logout</a></p>";
        } else {
            return "<h1>Welcome!</h1>" +
                   "<p>You are not authenticated. Please navigate to IdP to initiate SAML login.</p>" +
                   "<p>Or try Spring Security's default <a href='/login'>login page</a>.</p>";
        }
    }

    @GetMapping("/user-info")
    public String userInfo(HttpSession session) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication instanceof SamlAuthenticationToken) {
            SamlAuthenticationToken samlAuth = (SamlAuthenticationToken) authentication;
            Map<String, String> attributes = samlAuth.getAttributes();
            StringBuilder sb = new StringBuilder("<h1>SAML User Attributes</h1>");
            sb.append("<ul>");
            attributes.forEach((key, value) -> sb.append("<li><strong>").append(key).append(":</strong> ").append(value).append("</li>"));
            sb.append("</ul>");
            sb.append("<p><a href='/'>Back to Home</a></p>");
            return sb.toString();
        } else {
            Map<String, String> attributes = (Map<String, String>) session.getAttribute("samlUserAttributes");
            if (attributes != null) {
                StringBuilder sb = new StringBuilder("<h1>SAML User Attributes from Session</h1>");
                sb.append("<ul>");
                attributes.forEach((key, value) -> sb.append("<li><strong>").append(key).append(":</strong> ").append(value).append("</li>"));
                sb.append("</ul>");
                sb.append("<p><a href='/'>Back to Home</a></p>");
                return sb.toString();
            }
            return "<h1>Not a SAML authenticated user or attributes not found.</h1>" +
                   "<p><a href='/'>Back to Home</a></p>";
        }
    }
}

// SAML Processing Service
@Service
class SamlProcessorService {

    private static final Logger logger = Logger.getLogger(SamlProcessorService.class.getName());

    public Map<String, String> processSamlResponse(String samlResponseEncoded, HttpSession session) throws Exception {
        logger.info("Starting SAML response processing.");

        // 1. Base64 Decode the SAML Response
        byte[] decodedBytes = Base64.getDecoder().decode(samlResponseEncoded);
        String samlXml = new String(decodedBytes, StandardCharsets.UTF_8);
        logger.fine("Decoded SAML XML: " + samlXml);

        // 2. Parse the XML Document
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true); // Crucial for XPath with namespaces
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(new InputSource(new StringReader(samlXml)));

        // 3. Initialize XPath with SAML namespaces
        XPath xpath = XPathFactory.newInstance().newXPath();
        xpath.setNamespaceContext(new SamlNamespaceContext());

        // --- Simplified Validation (Production requires extensive validation!) ---
        // For a real SP, you would validate:
        // - Signature of the Response/Assertion (against IdP's public key)
        // - InResponseTo attribute (if SP initiated login)
        // - Recipient (your ACS URL)
        // - NotBefore/NotOnOrAfter timestamps
        // - AudienceRestriction (your SP's Entity ID)
        // - Status Code (samlp:Response/samlp:Status/samlp:StatusCode)

        // 4. Extract Assertion and Subject NameID
        Node assertionNode = (Node) xpath.evaluate("//saml:Assertion", doc, XPathConstants.NODE);
        if (assertionNode == null) {
            throw new Exception("SAML Assertion not found in the response.");
        }

        String nameId = (String) xpath.evaluate("saml:Subject/saml:NameID", assertionNode, XPathConstants.STRING);
        if (nameId == null || nameId.isEmpty()) {
            throw new Exception("NameID not found in SAML Assertion.");
        }
        logger.info("Extracted NameID (Principal): " + nameId);

        Map<String, String> userAttributes = new HashMap<>();
        userAttributes.put("NameID", nameId); // Always include NameID as a primary attribute

        // 5. Extract Attributes from AttributeStatement
        NodeList attributeNodes = (NodeList) xpath.evaluate("saml:AttributeStatement/saml:Attribute", assertionNode, XPathConstants.NODESET);
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attributeElement = (Element) attributeNodes.item(i);
            String attributeName = attributeElement.getAttribute("Name");
            NodeList attributeValueNodes = (NodeList) xpath.evaluate("saml:AttributeValue", attributeElement, XPathConstants.NODESET);

            List<String> values = new ArrayList<>();
            for (int j = 0; j < attributeValueNodes.getLength(); j++) {
                Node valueNode = attributeValueNodes.item(j);
                if (valueNode != null) {
                    values.add(valueNode.getTextContent());
                }
            }
            // For simplicity, joining multiple values with a comma.
            // In a real application, you might store them as a List<String>.
            if (!values.isEmpty()) {
                userAttributes.put(attributeName, String.join(",", values));
                logger.fine("Extracted attribute: " + attributeName + " = " + String.join(",", values));
            }
        }

        // 6. Create an Authentication object and set it in SecurityContext
        List<GrantedAuthority> authorities = Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER")); // Assign default role
        SamlAuthenticationToken authentication = new SamlAuthenticationToken(nameId, authorities, userAttributes);
        SecurityContextHolder.getContext().setAuthentication(authentication);

        logger.info("Authentication successful for " + nameId);

        return userAttributes;
    }
}

// Helper class for SAML XML Namespace Context
class SamlNamespaceContext implements NamespaceContext {
    @Override
    public String getNamespaceURI(String prefix) {
        if (prefix.equals("samlp")) {
            return "urn:oasis:names:tc:SAML:2.0:protocol";
        } else if (prefix.equals("saml")) {
            return "urn:oasis:names:tc:SAML:2.0:assertion";
        }
        return null;
    }

    @Override
    public String getPrefix(String namespaceURI) {
        if (namespaceURI.equals("urn:oasis:names:tc:SAML:2.0:protocol")) {
            return "samlp";
        } else if (namespaceURI.equals("urn:oasis:names:tc:SAML:2.0:assertion")) {
            return "saml";
        }
        return null;
    }

    @Override
    public Iterator<String> getPrefixes(String namespaceURI) {
        // Not used by XPath engine for evaluating expressions
        return null;
    }
}